define("confluence-job", {
  prefix: "confluencepro.job.",
  keys: [
    "question.additionalInfo.documentsCount",
    "question.additionalInfo.attachmentsCount",
    "question.showMore.message",
    "question.showMore.link",
    "status.runningJob",
  ],
});
define("confluencepro-migration-raport", {
  prefix: "confluencepro.migration.raport.",
  keys: [
    "macros.count",
    "macros.document",
    "unfoldall",
    "foldall",
    "problems.confluencerefs.list",
    "problems.confluencerefids.list",
    "doctreefailure",
    "loadsectionfailure",
    "renamingSpace",
    "confluencespace",
    "pageTitle",
    "macroName",
    "parameterName",
    "parameterValues",
  ],
});

require(["jquery", "xwiki-l10n!confluence-job", "xwiki-l10n!confluencepro-migration-raport", "xwiki-job-runner"], function (
  $,
  l10n,
  i18n,
  JobRunner,
) {
  let checkedValues = new Set();
  // Send search request to server and update the displayed questions.
  let searchAndDisplay = function (url, qSearch, offset) {
    if (!url) {
      return;
    }
    let template = $(".available-space.hidden");
    $.getJSON(url + "&qSearch=" + qSearch + "&offset=" + offset).done(
      function (data) {
        if (offset == 0) {
          $(".available-space").each(function () {
            if (
              this.className === "available-space" &&
              !$(this).find("input").prop("checked")
            ) {
              this.remove();
            }
          });
        }
        let createdElements = [];
        data.results.forEach(function (space, index) {
          if (checkedValues.has(space.reference)) {
            return;
          }
          let element = template.clone();
          element.toggleClass("hidden");
          element
            .find("label")
            .attr("for", "confluence_space_" + index)
            .append(document.createTextNode(space.reference));
          if (space.properties.name) {
            let spaceTitle = document.createElement("span");
            spaceTitle.append(document.createTextNode(' - ' + space.properties.name));
            element.find("label").append(spaceTitle);
            delete space.properties.name;
          }
          element
            .find("input")
            .attr("id", "confluence_space_" + index)
            .prop("disabled", false)
            .val(space.reference);
          createdElements.push(element);
          for (const [key, value] of Object.entries(space.properties)) {
            element
              .find(".cfmProperties")
              .append(
                "<span>" +
                  l10n["question.additionalInfo." + key] +
                  " " +
                  value +
                  "</span>",
              );
          }
        });
        $(".ui-question").trigger("confluence:job:spaces:loaded", [
          createdElements,
        ]);
        createdElements.each(function (elem) {
          $(".available-spaces").append(elem);
        });
        let remaining = data.total - (offset + data.results.length);
        if (remaining > 0) {
          $(".cfmShowMoreGroup").removeClass("hidden");
          $(".cfmShowMoreMessage").text(
            l10n.get("question.showMore.message", remaining),
          );
          $(".cfmShowMoreLink")
            .text(l10n.get("question.showMore.link"))
            .data("offset", data.total - remaining);
        } else {
          $(".cfmShowMoreGroup").addClass("hidden");
        }
      },
    );
  };
  let initQuestion = function () {
    $(".job-loading-status").hide();
    $(this)
      .find(".btn-primary")
      .on("click", function () {
        $(".job-loading-status").show();
        $(".job-loading-status .loading-text").text(
          l10n.get("status.runningJob"),
        );
      });
    searchAndDisplay($(".cfmSearch input").data("url"), "", 0);
  };
  // Add listener to the show more link.
  $(document).on("click", ".cfmShowMoreLink", function (event) {
    event.preventDefault();
    let offset = $(this).data("offset");
    if (offset) {
      searchAndDisplay(
        $(".cfmSearch input").data("url"),
        $(".cfmSearch input").val(),
        offset,
      );
    }
  });
  // Add listener to job question search input.
  let timeout;
  $(document).on("input", ".cfmSearch input", function () {
    if (timeout) {
      clearTimeout(timeout);
    }
    let input = $(this);
    timeout = setTimeout(function () {
      searchAndDisplay(input.data("url"), input.val(), 0);
    }, 1000);
  });
  // Add listener to selectall checkbox.
  $(document).on("change", "#cfmSelectAllInput", function () {
    $(".available-space input").prop("checked", $(this).prop("checked"));
  });
  $(document).on("change", ".available-space input", function () {
    if (!$(this).prop("checked")) {
      checkedValues.delete($(this).val());
      $("#cfmSelectAllInput").prop("checked", false);
    } else {
      checkedValues.add($(this).val());
    }
  });
  $(".ui-question").each(function () {
    let uiQuestion = $(this);
    // Register for any event in the future
    uiQuestion.on("job:question:loaded", initQuestion);
  });
  $(".job-status").on("xwiki:job:done", function () {
    const interro = location.href.indexOf('?');
    if (interro === -1) {
      location.reload();
    } else {
      // We don't want parameters like fulljoblogs to stay
      location.href = location.href.substring(0, interro);
    }
  });
  document.getElementById("cfmInterrupt")
    ?.addEventListener("click", function (e) {
      if (confirm("Are you sure you want to interrupt this migration?")) {
        const cancelButton = document.querySelector("button.btAnswerCancel");
        if (cancelButton) {
          cancelButton.click();
        } else {
          $.ajax("?interrupt=1", {
            method: "POST",
            contentType: "text/plain",
            data: "0",
          });
        }
      }
    });

  function handleUnfoldAll(e) {
    const ul = e?.target?.parentNode?.nextElementSibling;
    if (ul) {
      for (const a of ul.querySelectorAll('a[aria-expanded="false"]')) {
        a.click();
      }

      for (const details of ul.getElementsByTagName('details')) {
        details.open = true;
      }
    }
  }

  function handleFoldAll(e) {
    const ul = e?.target?.parentNode?.nextElementSibling;
    if (ul) {
      for (const a of ul.querySelectorAll('a[aria-expanded="true"]')) {
        a.click();
      }

      for (const details of ul.getElementsByTagName('details')) {
        details.open = false;
      }
    }
  }

  $(".cfm-unfold-all").on("click", handleUnfoldAll);
  $(".cfm-fold-all").on("click", handleFoldAll);

  function format(message, args) {
    const m = message.split("{}");
    let res = m[0];
    for (let i = 1; i < m.length; i++) {
      res += args[i - 1] + m[i];
    }
    return res;
  }

  function parse(l, method) {
    if (method === "attachment") {
      return l;
    }

    if (!l.trim()) {
      return null;
    }
    try {
      return JSON.parse(l);
    } catch (e) {
      console.log("Could not parse the following JSON line:", l, e);
      return null;
    }
  }

  function lines(jsonLogs, method) {
    if (method === "attachment") {
      return jsonLogs;
    }

    return jsonLogs.split("\n");
  }

  const logs = document.getElementById("cfmLogs");
  if (logs) {
    const fullLogsBtn = document.getElementById("cfm-full-logs");
    if (fullLogsBtn) {
      fullLogsBtn.onclick = function (e) {
        getLogs();
        e.preventDefault();
      }
    } else {
      getLogs();
    }
  }

  function renderReferenceNicely(ref) {
    if (ref.includes(".")) {
      const r = XWiki.Model.resolve(ref, XWiki.EntityType.DOCUMENT);
      const d = new XWiki.Document(r);
      const a = document.createElement("a");
      a.href = d.getURL();
      a.textContent = r.getReversedReferenceChain()
        .filter(({type}) => type == XWiki.EntityType.SPACE)
        .map(({name}) => name)
        .join(" > ")
      return a;
    }

    return ref;
  }

  function getLogs() {
    // if method === "attachment", the logs were saved as an attachments (old
    // migrations, we don't do it like this anymore), and we shall use it
    // instead of the log tail because PageIdentifier objects in these logs are
    // not parsed correctly
    const method = logs.dataset.logMethod;

    const logsURL = method === "attachment"
      ? XWiki.currentDocument.getURL("download") + "/logs.json"
      : new XWiki.Document(new XWiki.DocumentReference(
            XWiki.currentWiki,
            ["ConfluenceMigratorPro", "Code"],
            "Logs"
        )).getURL("get") + "?action=alllogs&name=" + encodeURIComponent(XWiki.currentDocument.page);

    $.get(logsURL).then(function (jsonLogs) {
      const ul = document.createElement("ul");
      ul.className = "log";
      for (const l of lines(jsonLogs, method)) {
        const log = parse(l, method);
        if (!log) {
          continue;
        }
        const li = document.createElement("li");
        li.className = "log-item log-item-" + (log.level?.toLowerCase() || "");
        const div = document.createElement("div");
        const d = new Date(log.timeStamp);
        const datetime = d.toLocaleDateString() + " " + d.toLocaleTimeString();
        const msg = log.args ? format(log.message, log.args) : log.message;
        div.textContent = datetime + " " + msg;
        li.appendChild(div);
        if (log.throwable) {
          const divStack = document.createElement("div");
          divStack.className = "stacktrace";
          divStack.textContent = log.throwable.join("\n");
          li.appendChild(divStack);
        }
        ul.appendChild(li);
      }
      logs.textContent = "";
      logs.appendChild(ul);
    });
  }

  function displayFoldingButtons() {
    const p = document.createElement("p");
    const unfold = document.createElement("button");
    unfold.className = "cfm-unfold-all btn";
    const fold = document.createElement("button");
    fold.className = "cfm-fold-all btn";
    fold.type = unfold.type = "button";
    unfold.textContent = i18n.get("unfoldall");
    fold.textContent = i18n.get("foldall");
    $(unfold).click(handleUnfoldAll);
    $(fold).click(handleFoldAll);
    p.append(unfold, " ", fold);
    return p;
  }

  function renderSerializedReference(r) {
    const p = (r.parent ? (renderSerializedReference(r.parent) + (r.parent.type === "WIKI" ? ":" :  ".")) : '');
    return p + (r.name || "").replaceAll('.', '\\.');
  }

  function formatProblem(msg, args) {
    let res = msg;
    for (const arg of args) {
      let renderedArg = arg;
      if (typeof arg !== "string") {
        renderedArg = (arg.parent && arg.name)
          ? renderSerializedReference(arg)
          : JSON.stringify(arg);
      }
      res = res.replace("{}", renderedArg);
    }
    return res;
  }

  function filterCurrentRevision(json) {
    const oldreverrors = document.location.search.includes("oldreverrors=1");
    const res = {};
    for (const [k, v] of Object.entries(json)) {
      const lines = [];
      if (v) {
        for (const logline of v) {
          const data = logline.data;
          if (!data) {
            // Old report without data about old revisions
            return json;
          }
          if (oldreverrors || (!logline.originalVersion || logline.originalVersion == logline.pageId)) {
            lines.push(data);
          }
        }

        if (lines.length > 0) {
          res[k] = lines;
        }
      }
    }

    return res;
  }

  function displayJSON(json) {
    const f = document.createDocumentFragment();
    const foldingButtons = displayFoldingButtons();
    const ul = document.createElement("ul");
    ul.className = "cfm-problem-pages";
    for (const [k, problems] of Object.entries(json)) {
      if (problems.length == 0) {
        continue;
      }
      const li = document.createElement("li");
      const details = document.createElement("details");
      details.className = "cfm-details";
      const summary = document.createElement("summary");
      summary.append(renderReferenceNicely(k));
      const problemsUL = document.createElement("ul");
      problemsUL.className = "cfm-problems";
      details.append(summary, problemsUL);
      li.append(details);
      ul.append(li);
      for (const problem of problems) {
        const problemLI = document.createElement("li");
        problemLI.className = "cfm-problem";
        problemLI.textContent = problem.msg ? formatProblem(problem.msg, problem.args) : JSON.stringify(problem);
        problemsUL.append(problemLI);
      }
    }
    f.append(foldingButtons, ul);
    return f;
  }

  async function getAndDisplayJSON(name) {
    const response = await fetch(XWiki.currentDocument.getURL("download") + "/" + name + ".json");
    if (response.ok) {
      const json = filterCurrentRevision(await response.json());
      return displayJSON(json);
    } else {
      alert(i18n.get("loadsectionfailure"));
    }

    return i18n.get("loadsectionfailure");
  }

  function getLoadingIcon() {
    const loading = document.createElement("div");
    loading.className = "loading-icon loading";
    return loading;
  }

  function entitiesEqual(a, b) {
    if (a == null && b == null) {
      return true;
    }

    return a?.name === b?.name && entitiesEqual(a.parent, b.parent);
  }

  function addSpaceToDocTree(rootSpace, context, docTree, spaceRef) {
    const initialParentSpace = context.parentSpace;
    const p = spaceRef.parent;
    if (!p || entitiesEqual(p, rootSpace) ||  p.type === XWiki.EntityType.WIKI) {
      context.parentSpace = docTree;
    } else {
       addSpaceToDocTree(rootSpace, context, docTree, p);
       context.parentSpace = context.space;
    }
    const n = spaceRef.getName();
    context.space = context.parentSpace.get(n);
    if (!context.space) {
      context.space = new Map();
      context.parentSpace.set(n,context.space);
    }
    context.parentSpace = initialParentSpace;
  }

  function addDocToDocTree(rootSpace, context, docTree,  docRef) {
    const p = docRef.parent;
    if (!p || entitiesEqual(p, rootSpace) ||  p.type === XWiki.EntityType.WIKI) {
      context.space = docTree;
    } else {
      addSpaceToDocTree(rootSpace, context, docTree, p);
    }
    context.space.set(docRef.getName(), docRef);
  }

  function displayRenaming(name, spaceTargets) {
    return name === spaceTargets[name]
      ? ""
      : " " + i18n.get('renamingSpace', spaceTargets[name]);
  }

  function printDocTree(tree, spaceTargets, isRoot) {
    const ul = document.createElement("ul");
    for (const [name, child] of tree.entries()) {
      if (name === "WebHome") {
        continue;
      }

      const li = document.createElement("li");
      ul.append(li);
      if (child instanceof Map) {
        const webHome = child.get("WebHome");
        if (webHome && child.size == 1) {
          li.className = "cfm-doc-tree-leaf";
          const a = document.createElement("a");
          li.append(a);
          a.href = new XWiki.Document(webHome).getURL();
          a.textContent = name;
          if (isRoot) {
            const renaming = displayRenaming(name, spaceTargets);
            if (renaming) {
              li.append(renaming);
            }
          }
        } else {
          const details = document.createElement("details");
          li.append(details);
          const summary = document.createElement("summary");
          details.append(summary);
          if (webHome) {
            const a = document.createElement("a");
            summary.append(a);
            a.href = new XWiki.Document(webHome).getURL();
            a.textContent = name;
          } else {
            summary.textContent = name;
            if (isRoot) {
              const renaming = displayRenaming(name, spaceTargets);
              if (renaming) {
                summary.append(renaming);
              }
            }
          }
          details.append(printDocTree(child, spaceTargets, false));
        }
      } else {
        li.className = "cfm-doc-tree-leaf";
        const a = document.createElement("a");
        li.append(a);
        a.href = new XWiki.Document(child).getURL();
        a.textContent = name;
      }
    }
    return ul;
  }

  (async function loadDocTree() {
    const divDocTree = document.getElementById("cfm-doc-tree");
    if (!divDocTree) {
      return;
    }

    const loading = getLoadingIcon();

    try {
      divDocTree.append(loading);
      let response = await fetch(XWiki.currentDocument.getURL("download") + "/spaceTargets.json");
      if (response.ok) {
        const spaceTargets = await response.json();
        const docTree = new Map();
        const invertedSpaceTargets = {};
        for (const [k, v] of Object.entries(spaceTargets)) {
          invertedSpaceTargets[v] = k;
        }

        response = await fetch(XWiki.currentDocument.getURL("download") + "/docs.json");
        if (response.ok) {
          const rootSpace = XWiki.Model.resolve(divDocTree.dataset.rootSpace, XWiki.EntityType.SPACE);
          for (const docRefStr of await response.json()) {
            const docRef = XWiki.Model.resolve(docRefStr, XWiki.EntityType.DOCUMENT);
            addDocToDocTree(rootSpace, {}, docTree, docRef);
          }

          loading.remove();
          divDocTree.append(displayFoldingButtons(), printDocTree(docTree, invertedSpaceTargets, true));
        }
      } else {
        divDocTree.append(i18n.get("doctreefailure"));
      }
    } catch (e) {
      divDocTree.append(i18n.get("doctreefailure"));
      console.error(e);
    } finally {
      if (loading.parentNode) {
        loading.remove();
      }
    }
  })();

  (async function problemSections() {
    function handleProblemsSection(details) {
      async function handleToggle() {
        if (!details.open || details.dataset.loading) {
          // We load stuff only on open, not on close
          return;
        }

        const loading = getLoadingIcon();
        details.dataset.loading = 1;
        try {
          details.append(loading);

          const content = await getAndDisplayJSON(details.dataset.problemsName);
          loading.remove();
          details.append(content);
        } catch (e) {
          alert(i18n.get("loadsectionfailure"));
          console.error(e);
        } finally {
          delete details.dataset.loading;
          if (loading.parentNode) {
            loading.remove();
          }
        }
        details.removeEventListener("toggle", handleToggle);
      }

      details.addEventListener("toggle", handleToggle);
      if (details.open) {
        handleToggle();
      }
    }

    for (const details of document.querySelectorAll("[data-problems-name]")) {
      if (!details.querySelector("cfm-problem-pages")) {
        // Only handle sections not already loaded
        handleProblemsSection(details);
      }
    }
  })();

  (function unsupportedMacroDetails() {
    const details = document.getElementById("cfm-unsupported-macros-details");
    async function handleToggle() {
      if (!details.open || details.dataset.loading) {
        // We load stuff only on open, not on close
        return;
      }

      const unsupportedMacros = new Set(document.getElementById("cfm-unsupported-macros").textContent.split(",").map(s => s.trim().split(" ", 1)[0]));


      const loading = getLoadingIcon();
      details.dataset.loading = 1;
      try {
        details.append(loading);

        const response = await fetch(XWiki.currentDocument.getURL("download") + "/macroPages.json");
        if (response.ok) {
          const macroPages = await response.json();
          loading.remove();
          let found = false;
          let pageByMacro = {};
          for (const [documentReference, macroEntries] of Object.entries(macroPages)) {
            for ([macroName, count] of Object.entries(macroEntries)) {
              if (unsupportedMacros.has(macroName)) {
                let macro = pageByMacro[macroName]
                if (!macro) {
                  macro = pageByMacro[macroName] = {};
                }
                macro[documentReference] = count;
                found = true;
              }
            }
          }
          if (found) {
            const ul = document.createElement("ul");
            for (const [macroName, countByDocumentReference] of Object.entries(pageByMacro)) {
              const li = document.createElement("li");
              const innerDetails = document.createElement("details");
              innerDetails.className = "cfm-details";
              const summary = document.createElement("summary");
              const table = document.createElement("table");
              const tbody = document.createElement("tbody");
              table.append(tbody);
              const trHeader = document.createElement("tr");
              let th = document.createElement("th");
              th.className = "cfm-macro--count";
              th.textContent = i18n.get('macros.count');
              trHeader.append(th);
              th = document.createElement("th");
              th.textContent = i18n.get("macros.document");
              trHeader.append(th);
              tbody.append(trHeader);
              let total = 0;
              for ([documentReference, count] of Object.entries(countByDocumentReference)) {
                total += count;
                const tr = document.createElement("tr");
                let td = document.createElement("td");
                td.textContent = count;
                tr.append(td);
                td = document.createElement("td");
                td.append(renderReferenceNicely(documentReference));
                tr.append(td);
                tbody.append(tr);
              }
              summary.textContent = macroName + " (" + total + ")";
              innerDetails.append(summary, table);
              li.append(innerDetails);
              ul.append(li);
            }

            details.append(ul);
          } else {
            // Should not really happen
            const p = document.createElement("p");
            p.textContent = i18n.get("loadsectionfailure");
            details.append(p);
          }

          details.removeEventListener("toggle", handleToggle);
        }
      } catch (e) {
        alert(i18n.get("loadsectionfailure"));
        console.error(e);
      } finally {
        delete details.dataset.loading;
        if (loading.parentNode) {
          loading.remove();
        }
      }
    }

    if (details) {
      details.addEventListener("toggle", handleToggle);

      if (details.open) {
        handleToggle();
      }
    }
  })();

  (function referenceWarnings() {
    const details = document.getElementById("cfm-reference-warnings");
    async function handleToggle() {
      if (!details.open || details.dataset.loading) {
        return;
      }

      const loading = getLoadingIcon();
      details.dataset.loading = 1;
      try {
        details.append(loading);

        const response = await fetch(XWiki.currentDocument.getURL("download") + "/confluenceRefWarnings.json");
        if (response.ok) {
          loading.remove();
          const json = filterCurrentRevision(await response.json());
          const missingPages = new Set();
          const missingPagesIds = new Set();
          for (const v of Object.values(json)) {
            for (const log of v) {
               let pageTitle, spaceKey;
               if (log?.args?.length == 1) {
                 spaceKey = log.args[0];
                 pageTitle = "";
               } else {
                 [pageTitle, spaceKey] = log.args;
               }

               if (typeof spaceKey === "string") {
                 missingPages.add(spaceKey + "." + pageTitle);
               } else {
                 missingPagesIds.add(spaceKey);
               }
            }
          }
          const p = document.createElement("p");
          p.textContent = i18n.get("problems.confluencerefs.list");
          const d = document.createDocumentFragment();
          d.append(p);
          if (missingPages.size > 0) {
            const table = document.createElement("table");
            d.append(table);
            const tbody = document.createElement("tbody");
            table.append(tbody);
            const tr = document.createElement("tr");
            tbody.append(tr);
            let th = document.createElement("th");
            th.textContent = i18n.get("confluencespace");
            tr.append(th);
            th = document.createElement("th");
            th.textContent = i18n.get("pageTitle");
            tr.append(th);
            const sortedMissingPages = Array.from(missingPages);
            sortedMissingPages.sort();
            for (const missingPage of sortedMissingPages) {
              const p = missingPage.split('.', 2);
              const tr2 = document.createElement("tr");
              td = document.createElement("td");
              td.textContent = p[0];
              tr2.append(td);
              td = document.createElement("td");
              td.textContent = p[1];
              tr2.append(td);
              tbody.append(tr2);
            }
          }

          if (missingPagesIds.size > 0) {
            const sortedMissingPagesIds = Array.from(missingPagesIds);
            sortedMissingPagesIds.sort();
            d.append(l10n.get("problems.confluencerefids.list") + " " + sortedMissingPagesIds.join(", "));
          }
          details.append(d);
          details.removeEventListener("toggle", handleToggle);
        } else {
          alert(i18n.get("loadsectionfailure"));
        }
      } catch (e) {
        alert(i18n.get("loadsectionfailure"));
        console.error(e);
      } finally {
        delete details.dataset.loading;
        if (loading.parentNode) {
          loading.remove();
        }
      }
    }

    details.addEventListener("toggle", handleToggle);
    if (details.open) {
      handleToggle();
    }
  })();

  function addUnknownParameterWithValue(problematicParameters, macroName, paramName, paramValue) {
    let byMacro = problematicParameters[macroName];
    if (!byMacro) {
      byMacro = problematicParameters[macroName] = {};
    }

    let byParam = byMacro[paramName];
    if (!byParam) {
      byParam = byMacro[paramName] = new Set();
    }

    byParam.add((paramValue === null || typeof paramName === undefined) ? 'null' : paramValue)
  }

  (function unhandledParameters() {
    const details = document.getElementById("cfm-unhandled-parameters");
    async function handleToggle() {
      if (!this.open || details.dataset.loading) {
        return;
      }

      const loading = getLoadingIcon();
      details.dataset.loading = 1;
      try {
        details.append(loading);

        const problematicParameters = {};
        let response = await fetch(XWiki.currentDocument.getURL("download") + "/unhandledParameters.json");
        if (response.ok) {
          let json = filterCurrentRevision(await response.json());
          for (const v of Object.values(json)) {
            for (const log of v) {
              if (log.args.length === 3) {
                const [paramName, paramValue, macroName] = log.args;
                addUnknownParameterWithValue(problematicParameters, macroName, paramName, paramValue);
              }
            }
          }

          response = await fetch(XWiki.currentDocument.getURL("download") + "/unhandledParameterValues.json");
          if (response.ok) {
            json = filterCurrentRevision(await response.json());
            for (const v of Object.values(json)) {
              for (const log of v) {
                if (log.args.length === 3) {
                  const [paramValue, paramName, macroName] = log.args;
                  addUnknownParameterWithValue(problematicParameters, macroName, paramName, paramValue)
                }
              }
            }

            loading.remove();

            const table = document.createElement("table");
            const tbody = document.createElement("tbody");
            table.append(tbody);
            const trHeader = document.createElement("tr");
            tbody.append(trHeader);
            let th = document.createElement("th");
            th.textContent = i18n.get("macroName");
            trHeader.append(th);
            th = document.createElement("th");
            th.textContent = i18n.get("parameterName");
            trHeader.append(th);
            th = document.createElement("th");
            th.textContent = i18n.get("parameterValues");
            trHeader.append(th);

            for (const [macroName, macroValue] of Object.entries(problematicParameters)) {
              for (const [paramName, paramValue] of Object.entries(macroValue)) {
                const tr = document.createElement("tr");
                tbody.append(tr);
                let td = document.createElement("td");
                td.textContent = macroName;
                tr.append(td);
                td = document.createElement("td");
                td.textContent = paramName;
                tr.append(td);
                td = document.createElement("td");
                const v = Array.from(paramValue);
                v.sort();
                td.textContent = v.join(', ');
                tr.append(td);
              }
            }
            details.append(table);
            details.removeEventListener("toggle", handleToggle);
          } else {
            alert(i18n.get("loadsectionfailure"));
          }
        } else {
          alert(i18n.get("loadsectionfailure"));
        }
      } catch (e) {
        alert(i18n.get("loadsectionfailure"));
        console.error(e);
      } finally {
        delete details.dataset.loading;
        if (loading.parentNode) {
          loading.remove();
        }
      }
    }

    details.addEventListener("toggle", handleToggle);
    if (details.open) {
      handleToggle();
    }
  })();
});

require(['jquery'], function ($) {
  function handleFilterPropertyChange() {
    const input = document.getElementById(
      this.classList.contains('cfm-input-filter-property')
        ? 'cfm-input-properties'
        : 'cfm-output-properties'
    );

    if (input) {
      let json = {};
      try {
        json = JSON.parse(input.value);
      } catch (e) {
        console.error("Could not parse the json value of input", input, e);
      }
      json[this.dataset.key] = this.value;
      input.value = JSON.stringify(json);
    } else {
        console.error("BUG: could not find the input to update for this property", this);
    }
  };

  $('.cfm-input-filter-property').on('change', handleFilterPropertyChange);
  $('.cfm-output-filter-property').on('change', handleFilterPropertyChange);
});

.available-space {
  margin-top: .5em;
  padding-bottom: .5em;
  display: grid;
  grid-template-areas: "a b"
                       "c d";
  grid-template-columns: fit-content(1ch) 1fr;
  gap: 0 0.5em;
}

.available-space label {
  font-weight: normal;
  grid-area: b;
}

.available-space input {
  grid-area: a;
}

.available-space .cfmProperties {
  grid-area: d;
}

.available-space span {
  margin-right: 0.5em;
  font-weight: lighter;
}

.imported-spaces {
  list-style-type: none;
}

.imported-space {
  padding: 1em;
}

.cfmToolbar {
  display: flex;
  margin-bottom: 2em;
  align-items: flex-end;
  gap: 0 2em;
}

.cfmButtonGroup {
  margin-top: 2em;
}

.cfmShowMoreGroup {
  font-style: italic;
}

.job-loading-status {
  display: flex;
  align-items: center;
}

.loading-icon {
  height: 1em;
  width: 1em;
  margin-right: 1em;
}

.cfm-problem-pages {
  list-style: none;
}

.imported-macros {
  display: grid;
  grid-template-areas: "a b c";
  grid-template-columns: fit-content(30%) fit-content(1ch) auto;
  gap: .5em .5em;
  margin-bottom: 1em;
}

.imported-macros-title {
  font-weight: 700;
}

.imported-macros-icon.supported {
  color: @brand-success;
}
.imported-macros-icon.not-supported {
  color: @brand-warning;
}

.imported-macros-list span::after {
  content: ',';
}

.imported-macros-list span:last-child::after {
  content: '';
}

details.cfm-details {
  summary {
    display: list-item;

    h3 {
      display: inline;
    }

    &:has(> h3)::marker {
      font-size: 1.3em;
    }
  }

  ul {
    list-style: none;
  }
}

.xcontent.job-status:has(> dl.xform > dt > .collapsed) #partial-logs-note {
  display: none;
}

.log-item:has(>.fake-log-items) {
  display: none;
}

.edit_section {
  display: none;
}

#cfm-doc-tree {
  ul {
    list-style:none;
  }

  /* We don't use the native list marker because we want the item to be aligned
     with details elements in sibling list items */
  .cfm-doc-tree-leaf:before {
    content: " • ";
  }

  /* Get back the default details and summary behavior */
  details, summary {
    display: revert;
  }
}

.cfm-foldable-section {
  margin-bottom: 2rem;
  margin-top: 2rem;
  > summary {
    display: list-item;

    &::marker {
      font-size: 1.5em;
    }

    h2 {
      display:inline;
    }

    .cfmTitleIcon {
      display: none;
    }
  }
}

.cfm-macro-per-doc-count {
  width: 10ex;
}
